func TestRunGmailHistoryRefresh_AppliesDelta(t *testing.T) {
	home := t.TempDir()
	t.Setenv("HOME", home)
	configPath, tokenStorePath := withConfigPath(t)
	writeConfigPointingAt(t, configPath, "http://unused", "user@example.com")
	seedSendStore(t, tokenStorePath, "user@example.com", "gid-001")

	db, err := store.Open(filepath.Join(home, ".local", "share", "superhuman-pp-cli", "data.db"))
	if err != nil {
		t.Fatalf("open store: %v", err)
	}
	if err := db.SaveHistoryState(t.Context(), "user@example.com", "100", time.Now(), time.Now()); err != nil {
		t.Fatalf("save history: %v", err)
	}
	db.Close()

	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if !strings.Contains(r.URL.RawQuery, "startHistoryId=100") {
			t.Fatalf("query %q missing startHistoryId=100", r.URL.RawQuery)
		}
		_, _ = w.Write([]byte(`{
			"history": [
				{"id":"101","messagesAdded":[{"message":{"id":"msg-1","threadId":"thread-1","labelIds":["INBOX"],"historyId":"101"}}]}
			],
			"historyId": "102"
		}`))
	}))
	defer srv.Close()
	origBaseURL := gmail.BaseURL
	gmail.BaseURL = srv.URL
	t.Cleanup(func() { gmail.BaseURL = origBaseURL })

	result, err := runGmailHistoryRefreshImpl(t.Context(), &rootFlags{configPath: configPath})
	if err != nil {
		t.Fatalf("runGmailHistoryRefresh: %v", err)
	}
	if result.RowsAffected != 1 || result.HistoryID != "102" {
		t.Fatalf("result = %+v, want rows=1 history=102", result)
	}
}

